import numpy as np
from scipy.optimize import linear_sum_assignment
from pprint import pprint


def distribute_items(preferences, item_labels, character_labels):
    """
    Distribute items to characters based on their preferences with DEBUG logging.
    """
    num_characters, num_items = preferences.shape

    print(f"\n--- DEBUG START ---")
    print(f"Input Matrix Shape: {preferences.shape}")
    print(f"Characters provided: {len(character_labels)}")
    print(f"Items provided: {len(item_labels)}")

    # Sanity check for labels vs matrix dimensions
    if len(character_labels) != num_characters:
        print(
            f"!! WARNING: Matrix has {num_characters} rows but you provided {len(character_labels)} character labels.")
    if len(item_labels) != num_items:
        print(f"!! WARNING: Matrix has {num_items} cols but you provided {len(item_labels)} item labels.")

    # In this case, preferences are equivalent to costs
    cost_matrix = preferences

    # Ensure that the number of characters is less than or equal to the number of items
    if num_characters > num_items:
        raise ValueError("Number of characters should be less than or equal to the number of items.")

    # Solve the assignment problem using the Hungarian algorithm
    print("Running linear_sum_assignment...")
    row_indices, col_indices = linear_sum_assignment(cost_matrix)

    # Initialize the distribution dictionary
    distribution = {}
    total_cost = 0

    print("\n--- ASSIGNMENT DETAILS ---")
    # Assign items to characters based on the solution
    for character_idx, item_idx in zip(row_indices, col_indices):

        # Calculate cost for this specific assignment
        cost = cost_matrix[character_idx, item_idx]
        total_cost += cost

        # Get names (handle potential index errors safely for debug)
        c_name = character_labels[character_idx] if character_idx < len(
            character_labels) else f"Unknown_Char_{character_idx}"
        i_name = item_labels[item_idx] if item_idx < len(item_labels) else f"Unknown_Item_{item_idx}"

        print(f"[{character_idx}] {c_name:<20} <--- [{item_idx}] {i_name:<30} (Cost: {cost})")

        if c_name not in distribution:
            distribution[c_name] = []
        distribution[c_name].append(i_name)

    print(f"\nTotal Optimized Cost: {total_cost}")

    # Check for unassigned items
    assigned_item_indices = set(col_indices)
    all_item_indices = set(range(num_items))
    unassigned_indices = list(all_item_indices - assigned_item_indices)
    unassigned_indices.sort()

    print(f"\n--- UNASSIGNED ITEMS ({len(unassigned_indices)}) ---")
    if len(unassigned_indices) > 0:
        # Just printing the first 10 to avoid spamming console if list is huge
        for i in unassigned_indices[:10]:
            i_label = item_labels[i] if i < len(item_labels) else "Unknown"
            print(f"Unassigned Item [{i}]: {i_label}")
        if len(unassigned_indices) > 10:
            print(f"... and {len(unassigned_indices) - 10} more.")

    print(f"--- DEBUG END ---\n")

    return distribution

